prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?participant) AS ?totalParticipants) ?modelName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0ba102e82f484407a4dbcb9bcafdd920" .
  OPTIONAL { ?model bbo:name ?modelName . }

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?definitions .
  ?definitions tai:belongsTo ?model .
}
GROUP BY ?modelName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?participant) AS ?totalParticipants) (SAMPLE(?modelName) AS ?modelName) WHERE {
  ?model a bboExt:Model .

  {
    ?model tai:normalizedId "0ba102e82f484407a4dbcb9bcafdd920" .
  }
  UNION
  {
    ?model tai:originalId "0ba102e82f484407a4dbcb9bcafdd920" .
  }
  UNION
  {
    ?model bbo:id "0ba102e82f484407a4dbcb9bcafdd920" .
  }
  OPTIONAL { ?model bbo:name ?modelName . }

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?definitions .
  ?definitions tai:belongsTo ?model .
}
GROUP BY ?model

